const express = require('express');
const bodyParser = require('body-parser');
const { Client } = require('@elastic/elasticsearch');

const app = express();
app.use(bodyParser.json());

// Initialize Elasticsearch client with your cluster information
const esClient = new Client({ node: 'http://localhost:9200' });

async function search(query) {
  const { body } = await esClient.search({
    index: 'your_index', // replace with the name of your index
    body: {
      query: {
        bool: {
          must: [], // add your conditions here based on user input
        },
      },
      script_score: {
        source: `doc[_source.custom_field].value + scoreByUserScript`,
        params: {
          scoreByUserScript: query.userScript, // replace with the user-provided custom scoring script
        },
      },
    },
  });

  return body.hits.hits;
}

app.post('/search', async (req, res) => {
  const results = await search(req.body);
  res.json(results);
});

// Start the server on a specific port
const port = process.env.PORT || 3000;
app.listen(port, () => console.log(`Server started on port ${port}`));